  1	import React, { FC } from 'react';
  2	
  3	import { Button, FormFieldGroupExpandable, FormFieldGroupHeader } from '@patternfly/react-core';
  4	import { ClusterNetworkFeatures } from '@utils/hooks/useClusterNetworkFeatures';
  5	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
  6	import { NetworkPolicy, NetworkPolicyRule } from '@utils/models';
  7	
  8	import { NetworkPolicyEgressIngress } from '../utils/types';
  9	import { emptyRule } from '../utils/utils';
 10	
 11	import NetworkPolicyRuleConfigPanel from './NetworkPolicyRuleConfigPanel/NetworkPolicyRuleConfigPanel';
 12	
 13	type NetworkPolicyFormEgressProps = {
 14	  networkFeatures: ClusterNetworkFeatures;
 15	  networkFeaturesLoaded: boolean;
 16	  networkPolicy: NetworkPolicy;
 17	  onPolicyChange: (policy: NetworkPolicy) => void;
 18	  removeAll: (msg: string, execute: () => void) => void;
 19	};
 20	
 21	const NetworkPolicyFormEgress: FC<NetworkPolicyFormEgressProps> = ({
 22	  networkFeatures,
 23	  networkFeaturesLoaded,
 24	  networkPolicy,
 25	  onPolicyChange,
 26	  removeAll,
 27	}) => {
 28	  const { t } = useNetworkingTranslation();
 29	
 30	  if (
 31	    networkPolicy.egress.denyAll &&
 32	    networkFeaturesLoaded &&
 33	    networkFeatures.PolicyEgress !== false
 34	  )
 35	    return null;
 36	
 37	  const updateEgressRules = (rules: NetworkPolicyRule[]) =>
 38	    onPolicyChange({
 39	      ...networkPolicy,
 40	      egress: { ...networkPolicy.egress, rules },
 41	    });
 42	
 43	  const removeAllEgress = () => {
 44	    removeAll(
 45	      t('This action will remove all rules within the Egress section and cannot be undone.'),
 46	      () => updateEgressRules([]),
 47	    );
 48	  };
 49	
 50	  const addEgressRule = () => {
 51	    updateEgressRules([emptyRule(), ...networkPolicy.egress.rules]);
 52	  };
 53	
 54	  const removeEgressRule = (idx: number) => {
 55	    updateEgressRules([
 56	      ...networkPolicy.egress.rules.slice(0, idx),
 57	      ...networkPolicy.egress.rules.slice(idx + 1),
 58	    ]);
 59	  };
 60	
 61	  return (
 62	    <FormFieldGroupExpandable
 63	      className="co-create-networkpolicy__expandable-xl"
 64	      header={
 65	        <FormFieldGroupHeader
 66	          actions={
 67	            <>
 68	              <Button
 69	                data-test="remove-all-egress"
 70	                isDisabled={networkPolicy.egress.rules.length === 0}
 71	                onClick={removeAllEgress}
 72	                variant="link"
 73	              >
 74	                {t('Remove all')}
 75	              </Button>
 76	              <Button data-test="add-egress" onClick={addEgressRule} variant="secondary">
 77	                {t('Add egress rule')}
 78	              </Button>
 79	            </>
 80	          }
 81	          titleDescription={t(
 82	            'Add egress rules to be applied to your selected pods. Traffic is allowed to pods if it matches at least one rule.',
 83	          )}
 84	          titleText={{
 85	            id: 'egress-header',
 86	            text: t('Egress'),
 87	          }}
 88	        />
 89	      }
 90	      isExpanded
 91	      toggleAriaLabel="Egress"
 92	    >
 93	      {networkPolicy.egress.rules.map((rule, idx) => (
 94	        <NetworkPolicyRuleConfigPanel
 95	          direction={NetworkPolicyEgressIngress.egress}
 96	          key={rule.key}
 97	          onChange={(r) => {
 98	            const newRules = [...networkPolicy.egress.rules];
 99	            newRules[idx] = r;
100	            updateEgressRules(newRules);
101	          }}
102	          onRemove={() => removeEgressRule(idx)}
103	          policyNamespace={networkPolicy.namespace}
104	          rule={rule}
105	        />
106	      ))}
107	    </FormFieldGroupExpandable>
108	  );
109	};
110	
111	export default NetworkPolicyFormEgress;

